  ('retired-8b44517b-moex-00310', 'retired-8b44517b', 'retired-8b44517b-moex-110-d3ff7f6b', 'sub-retired-8b44517b-08', NULL, 'single_choice', '在其他條件不變下，如果蓮霧的肥料與農藥的價格大幅上漲，則關於蓮霧市場的變化，下列敘述 何者正確？', '["均衡交易量與均衡價格一起上升", "均衡交易量與均衡價格一起下跌", "均衡交易量上升，均衡價格下跌", "均衡交易量下跌，均衡價格上升"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:07+00:00", "source_pdf_sha1": "9d0f3ef7cefa", "answer_pdf_sha1": "c3c61d5d327e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "133", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00311', 'retired-8b44517b', 'retired-8b44517b-moex-110-d3ff7f6b', 'sub-retired-8b44517b-08', NULL, 'single_choice', '我們知道稻米或蔬菜通常需要種植一段時間才能在市場上販售，因此在短期間有關供給彈性敘述 下列何者正確？', '["其供給彈性固定為1", "其供給彈性須視替代產品多寡而定", "其供給彈性很大", "其供給彈性很小"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:07+00:00", "source_pdf_sha1": "9d0f3ef7cefa", "answer_pdf_sha1": "c3c61d5d327e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "133", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00312', 'retired-8b44517b', 'retired-8b44517b-moex-110-d3ff7f6b', 'sub-retired-8b44517b-08', NULL, 'single_choice', '小明與小華都喜歡看電影，但小明每月固定花 1000 元左右看電影，而小華則每月固定看兩場電 影，由此可知誰對電影的需求彈性較大？', '["小華", "小明", "一樣", "無法確定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:07+00:00", "source_pdf_sha1": "9d0f3ef7cefa", "answer_pdf_sha1": "c3c61d5d327e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "133", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00313', 'retired-8b44517b', 'retired-8b44517b-moex-110-d3ff7f6b', 'sub-retired-8b44517b-08', NULL, 'single_choice', '在臺灣的汽油市場上，假設政府為了提高能源使用效率，並促使國人節約使用能源，對廠商生產 的汽油課徵每公升1元的貨物稅，則下列敘述何者正確？', '["汽油市場的均衡價格會下降", "汽油市場的均衡消費量不變", "消費者與生產者雙方都會承擔稅負支出", "消費者的福利會隨課稅而增加"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:07+00:00", "source_pdf_sha1": "9d0f3ef7cefa", "answer_pdf_sha1": "c3c61d5d327e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "133", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00314', 'retired-8b44517b', 'retired-8b44517b-moex-110-d3ff7f6b', 'sub-retired-8b44517b-08', NULL, 'single_choice', '假設某消費者預算為100元，消費蘋果與橘子兩種商品。蘋果的單價是6元，橘子的單價是8元， 下列何種情況會讓此一消費者的預算限制式平行外移？', '["蘋果的單價變為12元，橘子的單價變為16元，該消費者預算仍為100元", "蘋果的單價變為12元，橘子的單價變為16元，該消費者預算變為200元", "蘋果的單價變為3元，橘子的單價變為4元，該消費者預算仍為100元", "蘋果與單價變為8元，橘子的單價變為6元，該消費者預算仍為100元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:07+00:00", "source_pdf_sha1": "9d0f3ef7cefa", "answer_pdf_sha1": "c3c61d5d327e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "133", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00315', 'retired-8b44517b', 'retired-8b44517b-moex-110-d3ff7f6b', 'sub-retired-8b44517b-08', NULL, 'single_choice', '下列何者為一家房屋建設公司的固定成本？', '["支付給建築公司工人每小時200元的工資", "每年支付給會計師事務所的年費5000元", "為工人支付的每小時2元的保險金", "每噸1000元的水泥"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:07+00:00", "source_pdf_sha1": "9d0f3ef7cefa", "answer_pdf_sha1": "c3c61d5d327e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "133", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00316', 'retired-8b44517b', 'retired-8b44517b-moex-110-d3ff7f6b', 'sub-retired-8b44517b-08', NULL, 'single_choice', '有關完全競爭市場與獨占性競爭市場之敘述，下列何者錯誤？', '["完全競爭市場中之產品為同質，獨占性競爭市場中之產品為異質", "完全競爭市場與獨占性競爭市場中廠商數目均很多", "完全競爭市場中的廠商為價格接受者，獨占性競爭市場中的廠商具有價格決定能力", "完全競爭市場中的廠商長期均衡利潤為零，獨占性競爭市場中的廠商長期下有正利潤"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:07+00:00", "source_pdf_sha1": "9d0f3ef7cefa", "answer_pdf_sha1": "c3c61d5d327e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "133", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00317', 'retired-8b44517b', 'retired-8b44517b-moex-110-d3ff7f6b', 'sub-retired-8b44517b-08', NULL, 'single_choice', '保留工資（reservationwage）是指：', '["廠商針對特殊能力的員工所提供的工資", "廠商針對例假日工作的員工所提供的工資", "勞工接受某一工作時，所要求的最低工資", "勞工的三節獎金"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:07+00:00", "source_pdf_sha1": "9d0f3ef7cefa", "answer_pdf_sha1": "c3c61d5d327e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "133", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00318', 'retired-8b44517b', 'retired-8b44517b-moex-110-d3ff7f6b', 'sub-retired-8b44517b-08', NULL, 'single_choice', '面對下列兩個抉擇：抉擇一，有10%的機率可以獲得$10,000，90%機率可以獲得$100；抉擇二， 獲取$1090。則下列敘述何者正確？', '["風險愛好者（risklover）會選擇抉擇一，風險趨避者（riskaverse）會選擇抉擇二", "風險愛好者會選擇抉擇二，風險趨避者會選擇抉擇一", "不論風險態度，都會選擇抉擇一", "不論風險態度，都會選擇抉擇二"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:07+00:00", "source_pdf_sha1": "9d0f3ef7cefa", "answer_pdf_sha1": "c3c61d5d327e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "133", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
